const timestamp = new Date().toISOString();
return [{
  json: {
    status: 'completed',
    message: 'No hay alquileres pendientes de verificar',
    verificadas: 0,
    confirmadas_404: 0,
    rescatadas_200: 0,
    errores: 0,
    timestamp
  }
}];

// ============================================================================
// Verificador Alquiler - Procesar respuesta HTTP
// v1.0.0 - Soporta pending + ghost properties
// ============================================================================

const item = $input.first();
const originalData = item.json;

const propiedadData = $('Split propiedades').first().json;
const diasDesdeAusencia = propiedadData.dias_desde_ausencia || 0;
const primeraAusenciaAt = propiedadData.primera_ausencia_at;
const origen = propiedadData.origen; // 'pending' o 'ghost'

const MAX_DIAS_PENDING = 7;

// HTTP Request con fullResponse devuelve statusCode en el json
// Con continueOnFail, errores vienen con $json.error
let statusCode = 0;
let isError = false;

if (originalData.statusCode) {
  statusCode = originalData.statusCode;
} else if (originalData.error) {
  isError = true;
  // Intentar extraer status code del error message
  const match = (originalData.message || '').match(/(\d{3})/);
  if (match) statusCode = parseInt(match[1]);
}

// ============================================================================
// LÓGICA DE DECISIÓN
// ============================================================================

let action = 'skip';
let newStatus = null;
let reason = '';

if (origen === 'ghost') {
  // Ghost: solo confirmar si HTTP 404
  if (statusCode === 404) {
    action = 'confirm';
    newStatus = 'inactivo_confirmed';
    reason = `Ghost: HTTP 404 confirmado (sin discovery hace ${diasDesdeAusencia} días)`;
  } else if (statusCode === 200) {
    action = 'skip';
    reason = `Ghost: HTTP 200 - propiedad sigue activa`;
  } else {
    action = 'skip';
    reason = `Ghost: HTTP ${statusCode} - no concluyente, reintentar`;
  }
} else {
  // Pending: lógica Flujo C
  if (!primeraAusenciaAt) {
    action = 'skip';
    reason = 'ERROR: primera_ausencia_at es NULL';
  } else if (statusCode === 404) {
    action = 'confirm';
    newStatus = 'inactivo_confirmed';
    reason = `HTTP 404 - Confirmado (ausente ${diasDesdeAusencia} días)`;
  } else if (diasDesdeAusencia >= MAX_DIAS_PENDING) {
    action = 'confirm';
    newStatus = 'inactivo_confirmed';
    reason = `Auto-confirmado: ${diasDesdeAusencia} días ausente (límite: ${MAX_DIAS_PENDING})`;
  } else if (statusCode === 200) {
    action = 'reactivate';
    newStatus = 'completado';
    reason = `HTTP 200 - Reapareció después de ${diasDesdeAusencia} días`;
  } else if (isError) {
    action = 'skip';
    reason = `Error de red/timeout - Reintentar (día ${diasDesdeAusencia}/${MAX_DIAS_PENDING})`;
  } else {
    action = 'skip';
    reason = `HTTP ${statusCode} - Esperar (día ${diasDesdeAusencia}/${MAX_DIAS_PENDING})`;
  }
}

return [{
  json: {
    id: propiedadData.id,
    url: propiedadData.url,
    fuente: propiedadData.fuente,
    codigo_propiedad: propiedadData.codigo_propiedad,
    primera_ausencia_at: primeraAusenciaAt,
    statusCode,
    isError,
    action,
    newStatus,
    reason,
    origen,
    diasDesdeAusencia,
    maxDiasPending: MAX_DIAS_PENDING,
    timestamp: new Date().toISOString()
  }
}];

// ============================================================================
// Verificador Alquiler - Resumen final
// ============================================================================

const results = $input.first().json.results || [];

let confirmadas = 0;
let reactivadas = 0;
let ghosts_detectados = 0;
let skipped = 0;

for (const r of results) {
  if (r.status === 'inactivo_confirmed') {
    confirmadas++;
    if (r.origen === 'ghost') ghosts_detectados++;
  } else if (r.status === 'completado') {
    reactivadas++;
  } else {
    skipped++;
  }
}

return [{
  json: {
    status: 'completed',
    flujo: 'Flujo C - Verificador Alquiler v1.0.0',
    timestamp: new Date().toISOString(),
    total_procesadas: results.length,
    confirmadas_inactivas: confirmadas,
    ghosts_detectados,
    reactivadas,
    skipped,
    propiedades: results.map(r => ({
      id: r.id,
      url: r.url,
      fuente: r.fuente,
      origen: r.origen,
      nuevo_status: r.status,
      fecha_inactivacion: r.fecha_inactivacion
    }))
  }
}];
